function safeArray(v) {
  return Array.isArray(v) ? v : [];
}

function normalizeToken(v) {
  if (v === null || v === undefined || v === '') return null;
  if (typeof v === 'number') return v;
  const s = String(v).trim().toLowerCase();
  const tokenMap = {
    'not_applicable': 'not_applicable',
    'not applicable': 'not_applicable',
    'not_specified': 'not_specified',
    'not specified': 'not_specified',
    'no_experience': 'no_experience',
    'no experience': 'no_experience',
    'нет опыта': 'no_experience',
    'не применимо': 'not_applicable',
    'не указано': 'not_specified'
  };
  if (tokenMap[s]) return tokenMap[s];
  const asNum = Number(s);
  return Number.isFinite(asNum) ? asNum : s;
}

function compareLevels(a, b) {
  if (typeof a === 'number' && typeof b === 'number') {
    if (a < b) return 'lower';
    if (a > b) return 'higher';
    return 'equal';
  }
  if (a === b) return 'equal';
  return 'unknown';
}

const root = $input.first().json;

const competencies = safeArray(root.competency_catalog?.competencies);
const rawSelfAssessments = safeArray(root.assessment_input?.self_assessments);
const syntheticEvidence = safeArray(root.normalized?.synthetic_evidence);
const learningByCompetency = root.learning_catalog?.by_competency || {};

const selfByCompetency = {};
for (const item of rawSelfAssessments) {
  if (!item?.competency_id) continue;
  selfByCompetency[item.competency_id] = {
    competency_id: item.competency_id,
    self_level: normalizeToken(item.self_level),
    self_comment: item.self_comment || '',
    manager_level: normalizeToken(item.manager_level),
    manager_comment: item.manager_comment || '',
    assessment_date: item.assessment_date || null,
    source: item.source || 'uploaded_self_assessment'
  };
}

const syntheticByCompetency = {};
for (const item of syntheticEvidence) {
  if (!item?.competency_id) continue;
  if (!syntheticByCompetency[item.competency_id]) {
    syntheticByCompetency[item.competency_id] = [];
  }
  syntheticByCompetency[item.competency_id].push(item);
}

return competencies.map(comp => {
  const competencyId = comp.competency_id;
  const sa = selfByCompetency[competencyId] || null;

  const selfLevel = sa?.self_level ?? null;
  const managerLevel = sa?.manager_level ?? null;

  const selfManagerRelation =
    selfLevel !== null && managerLevel !== null
      ? compareLevels(selfLevel, managerLevel)
      : 'missing';

  let alignment = null;
  if (selfManagerRelation === 'lower') alignment = 'underestimate';
  else if (selfManagerRelation === 'higher') alignment = 'overestimate';
  else if (selfManagerRelation === 'equal') alignment = 'aligned';

  const hasSelfAssessment = !!sa;
  const hasManagerCalibration = sa && managerLevel !== null;
  const calibrationConflict =
    hasSelfAssessment &&
    hasManagerCalibration &&
    selfManagerRelation !== 'equal' &&
    selfManagerRelation !== 'unknown';

  const confidenceHint =
    !hasSelfAssessment ? 'low'
    : calibrationConflict ? 'medium'
    : hasManagerCalibration ? 'high'
    : 'medium';

  const learningAssets = safeArray(learningByCompetency[competencyId]).slice(0, 5);

  return {
    json: {
      employee: root.employee,

      assessment_mode: root.workflow_config?.assessment_mode || 'matrix_only',
      performance_inference_allowed: !!root.workflow_config?.performance_inference_allowed,
      development_inference_allowed: !!root.workflow_config?.development_inference_allowed,

      competency_id: competencyId,
      competency_name: comp.competency_name || competencyId,
      group_name: comp.group_name || null,
      type: comp.type || 'unknown',

      levels: safeArray(comp.levels),
      signals: comp.signals || {
        jira: [],
        behavioral: [],
        skill_categories: []
      },

      self_assessment: sa ? {
        self_level: selfLevel,
        self_comment: sa.self_comment,
        manager_level: managerLevel,
        manager_comment: sa.manager_comment,
        assessment_date: sa.assessment_date,
        source: sa.source
      } : null,

      self_assessment_signals: {
        has_self_assessment: hasSelfAssessment,
        has_manager_calibration: hasManagerCalibration,
        self_vs_manager_relation: selfManagerRelation,
        self_vs_manager_gap:
          hasSelfAssessment && hasManagerCalibration
            ? selfManagerRelation !== 'equal' && selfManagerRelation !== 'unknown'
            : false,
        alignment,
        confidence_hint: confidenceHint
      },

      evidence: [],
      synthetic_evidence: safeArray(syntheticByCompetency[competencyId]),
      internal_learning_assets: learningAssets,

      meta: {
        source: 'build_competency_payloads_v3',
        self_assessment_used: hasSelfAssessment
      }
    }
  };
});

function safeArray(v) {
  return Array.isArray(v) ? v : [];
}

const x = $json || {};
const payload = x.output || x.response || x.result || x;

const allowedConfidence = ['low', 'medium', 'high'];
const allowedPriority = ['low', 'medium', 'high'];
const allowedAlignment = ['underestimate', 'overestimate', 'aligned', null];

return [{
  json: {
    competency_id: payload.competency_id || x.competency_id || null,
    self_level: payload.self_level ?? x.self_assessment?.self_level ?? null,
    manager_level: payload.manager_level ?? x.self_assessment?.manager_level ?? null,
    estimated_level: payload.estimated_level ?? null,
    confidence: allowedConfidence.includes(payload.confidence) ? payload.confidence : 'low',
    priority: allowedPriority.includes(payload.priority) ? payload.priority : 'medium',
    assessment: payload.assessment || '',
    development_focus: payload.development_focus || '',
    alignment: allowedAlignment.includes(payload.alignment) ? payload.alignment : null,
    self_vs_manager_gap:
      typeof payload.self_vs_manager_gap === 'boolean'
        ? payload.self_vs_manager_gap
        : !!x.self_assessment_signals?.self_vs_manager_gap,
    evidence_missing: safeArray(payload.evidence_missing),
    risk_flags: safeArray(payload.risk_flags)
  }
}];
